+@page "/board"
+@using sv_95c6ace0876e446a897a1616c45a82f8.Components.Board
+@rendermode InteractiveServer
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h3 class="mb-3">Project Board</h3>
+
+@if (loading)
+{
+    <div class="d-flex justify-content-center p-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error loading tasks:</strong> @errorMessage
+        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStats TotalCount="allTasks.Count"
+                TodoCount="todoTasks.Count"
+                InProgressCount="inProgressTasks.Count"
+                DoneCount="doneTasks.Count"
+                OverdueCount="overdueTasks.Count" />
+
+    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />
+
+    <div class="row g-3">
+        <KanbanColumn ColumnName="To Do"
+                      Tasks="filteredTodo"
+                      CanMoveLeft="false"
+                      CanMoveRight="true"
+                      OnMoveRight="task => MoveTask(task, \"In Progress\")"
+                      OnTaskCreated="HandleTaskCreated" />
+
+        <KanbanColumn ColumnName="In Progress"
+                      Tasks="filteredInProgress"
+                      CanMoveLeft="true"
+                      CanMoveRight="true"
+                      OnMoveLeft="task => MoveTask(task, \"To Do\")"
+                      OnMoveRight="task => MoveTask(task, \"Done\")"
+                      OnTaskCreated="HandleTaskCreated" />
+
+        <KanbanColumn ColumnName="Done"
+                      Tasks="filteredDone"
+                      CanMoveLeft="true"
+                      CanMoveRight="false"
+                      OnMoveLeft="task => MoveTask(task, \"In Progress\")"
+                      OnTaskCreated="HandleTaskCreated" />
+    </div>
+}
+
+@code {
+    private List<TaskItem> allTasks = new();
+    private string searchText = string.Empty;
+    private bool loading = true;
+    private string? errorMessage;
+
+    // Unfiltered groups (for stats)
+    private List<TaskItem> todoTasks = new();
+    private List<TaskItem> inProgressTasks = new();
+    private List<TaskItem> doneTasks = new();
+    private List<TaskItem> overdueTasks = new();
+
+    // Filtered groups (for display)
+    private List<TaskItem> filteredTodo = new();
+    private List<TaskItem> filteredInProgress = new();
+    private List<TaskItem> filteredDone = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        loading = true;
+        errorMessage = null;
+
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+            UpdateGroups();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            loading = false;
+        }
+    }
+
+    private void UpdateGroups()
+    {
+        todoTasks = allTasks.Where(t => t.Status == "To Do").ToList();
+        inProgressTasks = allTasks.Where(t => t.Status == "In Progress").ToList();
+        doneTasks = allTasks.Where(t => t.Status == "Done").ToList();
+        overdueTasks = allTasks.Where(t => t.DueDate < DateTime.Today && t.Status != "Done").ToList();
+
+        ApplyFilter();
+    }
+
+    private void ApplyFilter()
+    {
+        if (string.IsNullOrWhiteSpace(searchText))
+        {
+            filteredTodo = todoTasks;
+            filteredInProgress = inProgressTasks;
+            filteredDone = doneTasks;
+        }
+        else
+        {
+            filteredTodo = todoTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
+            filteredInProgress = inProgressTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
+            filteredDone = doneTasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
+        }
+    }
+
+    private void HandleSearchChanged(string value)
+    {
+        searchText = value;
+        ApplyFilter();
+    }
+
+    private async Task MoveTask(TaskItem task, string newStatus)
+    {
+        await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+        // Update local state
+        var index = allTasks.FindIndex(t => t.Id == task.Id);
+        if (index >= 0)
+        {
+            allTasks[index] = task with { Status = newStatus };
+        }
+        UpdateGroups();
+    }
+
+    private void HandleTaskCreated(TaskItem task)
+    {
+        allTasks.Add(task);
+        UpdateGroups();
+    }
+}
+

